import { IMessageDataWrapper, IMessageParser } from '@nitrots/nitro-renderer';

export interface IHotRoomInfo {
    virtualRoomId: number;
    name: string;
    userCount: number;
}

export class HotRoomsListParser implements IMessageParser {
    private _rooms: IHotRoomInfo[] = [];

    public flush(): boolean {
        this._rooms = [];
        return true;
    }

    public parse(wrapper: IMessageDataWrapper): boolean {
        if (!wrapper) return false;

        this._rooms = [];

        const count = wrapper.readInt();

        for (let i = 0; i < count; i++) {
            const virtualRoomId = wrapper.readInt();
            const name = wrapper.readString();
            const userCount = wrapper.readInt();

            this._rooms.push({
                virtualRoomId,
                name,
                userCount,
            });
        }

        return true;
    }

    public get rooms(): IHotRoomInfo[] {
        return this._rooms;
    }
}
